mapper.select:
SELECT id, user_id, title, content, view_count, created_at, updated_at
FROM boards
WHERE id = #{id}

mapper.update:
UPDATE boards
SET view_count = view_count + 1
WHERE id = #{id}

mapper.select:
SELECT b.id, b.user_id, b.title, b.view_count, b.created_at, u.name AS user_name FROM boards b INNER JOIN users u ON b.user_id = u.id
(b.title LIKE CONCAT('%', #{keyword}, '%') OR b.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.created_at DESC LIMIT #{limit} OFFSET #{offset}
